#include <stdio.h>
#include <stdlib.h>

#define MAXN 500000
#define MOD 10000

int main(void) {
    static int prod[MAXN + 1];
    for (int i = 0; i <= MAXN; ++i) prod[i] = 1;
    for (int i = 1; i <= MAXN / 2; ++i) {
        for (int j = i * 2; j <= MAXN; j += i) {
            prod[j] = (prod[j] * i) % MOD;
        }
    }
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        printf("%d\n", prod[n]);
    }
    return 0;
}

